^grammar:v0.3
# deploy status, dense v0.3 form
@billing-api := svc:billing-api/staging
@v := 1.7.2
@p95 := 240ms
@migration := step:migration
@cache := step:cache-warmer
get @billing-api status ^3
run deploy @v -> done ^3
say pods healthy ^3
say latency @p95 ^3
say @migration *>> @cache ^3
